UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=sHQCPbeJD0k', conteudo_texto = '<h2>Brasil Atual</h2><p>Panorama da <strong>política, economia e sociedade brasileira</strong> para concursos da Petrobras.</p><h3>🏛️ Cenário Político</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><h4>Estrutura do Governo</h4><ul><li><strong>Governo Federal:</strong> Presidente eleito, mandato de 4 anos com reeleição.</li><li><strong>Congresso Nacional:</strong> 513 deputados + 81 senadores.</li><li><strong>STF:</strong> 11 ministros, última instância do Judiciário.</li></ul></div><h3>📊 Economia Brasileira</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Indicador</th><th style=''padding:10px;border:1px solid #ddd;''>O que é</th><th style=''padding:10px;border:1px solid #ddd;''>Quem define/mede</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>PIB</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Soma das riquezas produzidas</td><td style=''padding:10px;border:1px solid #ddd;''>IBGE</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>IPCA</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Inflação oficial</td><td style=''padding:10px;border:1px solid #ddd;''>IBGE</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Taxa Selic</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Taxa básica de juros</td><td style=''padding:10px;border:1px solid #ddd;''>COPOM/Banco Central</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Dólar</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Câmbio flutuante</td><td style=''padding:10px;border:1px solid #ddd;''>Mercado</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Desemprego</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Taxa de desocupação</td><td style=''padding:10px;border:1px solid #ddd;''>IBGE (PNAD)</td></tr></table></div><h3>⛽ Setor de Energia e Petróleo</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:250px;background:#d4edda;padding:15px;border-radius:8px;border-left:4px solid #28a745;''><h4>🛢️ Petrobras</h4><ul><li>Maior empresa do Brasil</li><li>Líder em águas profundas</li><li>Pré-sal: +70% da produção</li><li>Produção: ~3 milhões barris/dia</li><li>Autossuficiência em petróleo</li></ul></div><div style=''flex:1;min-width:250px;background:#fff3cd;padding:15px;border-radius:8px;border-left:4px solid #ffc107;''><h4>🔋 Matriz Energética</h4><ul><li>Hidrelétrica: ~60%</li><li>Eólica: ~12% (em expansão)</li><li>Solar: ~4% (crescendo)</li><li>Biomassa: ~8%</li><li>Uma das mais limpas do mundo</li></ul></div></div><h3>🌱 Meio Ambiente</h3><div style=''background:#d4edda;padding:15px;border-radius:8px;margin:15px 0;''><h4>Temas em Destaque</h4><ul><li><strong>Amazônia:</strong> Desmatamento, fiscalização, créditos de carbono.</li><li><strong>Transição energética:</strong> Investimentos em renováveis, hidrogênio verde.</li><li><strong>Acordo de Paris:</strong> Metas de redução de emissões até 2030.</li><li><strong>ESG:</strong> Governança ambiental exigida por investidores.</li></ul></div><h3>👥 Questões Sociais</h3><table style=''width:100%;border-collapse:collapse;margin:15px 0;''><tr style=''background:#6c757d;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Tema</th><th style=''padding:10px;border:1px solid #ddd;''>Contexto Atual</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Educação</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Novo Ensino Médio, ENEM, expansão do ensino técnico</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Saúde</strong></td><td style=''padding:10px;border:1px solid #ddd;''>SUS, vacinação, lições pós-pandemia</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Segurança</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Violência urbana, crime organizado, facções</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Desigualdade</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Concentração de renda, programas sociais</td></tr></table><h3>🔧 Reformas Recentes</h3><div style=''display:flex;flex-wrap:wrap;gap:10px;margin:15px 0;''><span style=''background:#007bff;color:white;padding:8px 12px;border-radius:20px;''>Reforma Tributária</span><span style=''background:#28a745;color:white;padding:8px 12px;border-radius:20px;''>Marco do Saneamento</span><span style=''background:#ffc107;color:black;padding:8px 12px;border-radius:20px;''>Nova Lei de Licitações</span><span style=''background:#dc3545;color:white;padding:8px 12px;border-radius:20px;''>Autonomia do BC</span><span style=''background:#6f42c1;color:white;padding:8px 12px;border-radius:20px;''>Marco das Garantias</span></div><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>A Cesgranrio cobra muito o <strong>setor de energia</strong>. Saiba os principais campos do pré-sal: <strong>Lula, Búzios, Tupi, Sapinhoá</strong>!</p></div>' WHERE titulo = 'Resumo: Brasil Atual';

UPDATE conteudos SET video_url = 'https://www.youtube.com/watch?v=P9R5WMO6haI', conteudo_texto = '<h2>Cenário Internacional</h2><p>Panorama da <strong>geopolítica e relações internacionais</strong> relevantes para concursos.</p><h3>🌍 Ordem Mundial Atual</h3><div style=''background:#e8f4f8;padding:15px;border-radius:8px;margin:15px 0;''><p>Vivemos um período de <strong>transição multipolar</strong>:</p><ul><li><strong>EUA:</strong> Ainda maior potência militar e econômica.</li><li><strong>China:</strong> Segunda economia, disputa hegemonia tecnológica.</li><li><strong>União Europeia:</strong> Bloco econômico integrado.</li><li><strong>Rússia:</strong> Potência militar e energética.</li><li><strong>Emergentes:</strong> BRICS ganhando relevância.</li></ul></div><h3>⚔️ Principais Conflitos e Tensões</h3><div style=''background:#f8d7da;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#dc3545;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Conflito</th><th style=''padding:10px;border:1px solid #ddd;''>Contexto</th><th style=''padding:10px;border:1px solid #ddd;''>Impacto Global</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Guerra Rússia-Ucrânia</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Iniciada em 2022, disputa territorial</td><td style=''padding:10px;border:1px solid #ddd;''>Crise energética, inflação, grãos</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Tensão EUA-China</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Disputa comercial e tecnológica</td><td style=''padding:10px;border:1px solid #ddd;''>Chips, Taiwan, 5G</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>Oriente Médio</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Conflitos históricos, questão palestina</td><td style=''padding:10px;border:1px solid #ddd;''>Petróleo, instabilidade regional</td></tr></table></div><h3>🏛️ Organismos Internacionais</h3><div style=''background:#f0f0f0;padding:15px;border-radius:8px;margin:15px 0;''><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#0066cc;color:white;''><th style=''padding:10px;border:1px solid #ddd;''>Organismo</th><th style=''padding:10px;border:1px solid #ddd;''>Função Principal</th><th style=''padding:10px;border:1px solid #ddd;''>Sede</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>ONU</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Paz, segurança, direitos humanos</td><td style=''padding:10px;border:1px solid #ddd;''>Nova York</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>FMI</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Estabilidade financeira global</td><td style=''padding:10px;border:1px solid #ddd;''>Washington</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>OMC</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Regras do comércio internacional</td><td style=''padding:10px;border:1px solid #ddd;''>Genebra</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>OPEP</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Coordena produção de petróleo</td><td style=''padding:10px;border:1px solid #ddd;''>Viena</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''><strong>OMS</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Saúde pública mundial</td><td style=''padding:10px;border:1px solid #ddd;''>Genebra</td></tr></table></div><h3>🤝 Blocos Econômicos</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;''><h4>🌎 BRICS</h4><ul><li>Brasil, Rússia, Índia, China, África do Sul</li><li>Expandido: Egito, Etiópia, Irã, Emirados, Arábia Saudita</li><li>Novo Banco de Desenvolvimento</li></ul></div><div style=''flex:1;min-width:200px;background:#fff3cd;padding:15px;border-radius:8px;''><h4>🇪🇺 União Europeia</h4><ul><li>27 países membros</li><li>Moeda única: Euro</li><li>Livre circulação</li></ul></div><div style=''flex:1;min-width:200px;background:#d1ecf1;padding:15px;border-radius:8px;''><h4>🌐 Mercosul</h4><ul><li>Brasil, Argentina, Uruguai, Paraguai</li><li>Associados: Chile, Colômbia, Peru</li><li>Acordo com UE em negociação</li></ul></div></div><h3>⛽ Mercado de Energia Global</h3><div style=''background:#fff3cd;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #ffc107;''><h4>🛢️ Petróleo e Gás</h4><table style=''width:100%;border-collapse:collapse;''><tr style=''background:#ffc107;''><th style=''padding:10px;border:1px solid #ddd;''>País</th><th style=''padding:10px;border:1px solid #ddd;''>Posição</th></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>EUA</td><td style=''padding:10px;border:1px solid #ddd;''>Maior produtor mundial</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''>Arábia Saudita</td><td style=''padding:10px;border:1px solid #ddd;''>Líder da OPEP</td></tr><tr><td style=''padding:10px;border:1px solid #ddd;''>Rússia</td><td style=''padding:10px;border:1px solid #ddd;''>Maior exportador de gás</td></tr><tr style=''background:#f9f9f9;''><td style=''padding:10px;border:1px solid #ddd;''><strong>Brasil</strong></td><td style=''padding:10px;border:1px solid #ddd;''>Top 10 produtores (pré-sal)</td></tr></table></div><h3>🌱 Transição Energética Global</h3><div style=''display:flex;gap:15px;margin:15px 0;flex-wrap:wrap;''><div style=''flex:1;min-width:200px;background:#d4edda;padding:15px;border-radius:8px;text-align:center;''><strong>🌞 Solar</strong><p>Crescimento exponencial</p><p>China lidera produção</p></div><div style=''flex:1;min-width:200px;background:#d1ecf1;padding:15px;border-radius:8px;text-align:center;''><strong>💨 Eólica</strong><p>Europa e China lideram</p><p>Offshore em expansão</p></div><div style=''flex:1;min-width:200px;background:#e8f4f8;padding:15px;border-radius:8px;text-align:center;''><strong>💧 Hidrogênio Verde</strong><p>Combustível do futuro</p><p>Brasil com potencial</p></div></div><h3>📋 Acordos Climáticos</h3><ul><li><strong>Acordo de Paris (2015):</strong> Limitar aquecimento a 1,5°C.</li><li><strong>COP:</strong> Conferência das Partes - reuniões anuais sobre clima.</li><li><strong>Net Zero:</strong> Meta de emissões líquidas zero até 2050.</li></ul><div style=''background:#d1ecf1;padding:15px;border-radius:8px;margin:15px 0;border-left:4px solid #17a2b8;''><h4>💡 Dica para Prova</h4><p>Cesgranrio adora perguntar sobre <strong>OPEP</strong> e o papel do Brasil no mercado de energia. Lembre: Brasil NÃO é membro da OPEP, mas é parceiro (OPEP+)!</p></div>' WHERE titulo = 'Resumo: Cenário Internacional';